<template>
    <section>
      <div class="modal my-popups right fade d-block" :class="{ show: isShown }">
                <div role="document" class="modal-dialog" style="max-width: 1300px !important;">
                <div class="modal-content">
                    <div class="modal-header mheader-user">
                        <button type="button" class="close" v-on:click="close()">
                            <i class="fa fa-times" aria-hidden="true"></i>
                        </button>
                        <h4 class="modal-title">{{ modelDetail.RULE_NAME? modelDetail.RULE_NAME : modelDetail.BILLING_RULE_NAME }}  </h4>
                    </div>
                    <div class="modal-body p-0">
                        <div class="tab-content" style="overflow-x: hidden; height: 800px;  max-height: 800px;"
                            v-if="modelDetail.CONFIGURATION_ID">
                            <FlowChartWrapper :configurationId="modelDetail.CONFIGURATION_ID.toString()" :isBillingType="isBillingType" :clientId="clientId"/>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </section>
</template>
<script>
import FlowChartWrapper from '../../views/BillingRule/ConfigurationComponent/VerticalFlowChart.vue';
export default {
    components: {
        FlowChartWrapper
    },
    props: {
        modelDetail: {
            type: [Object, Array],
            required: true
        },
         isBillingType :{
            type: Boolean,
            required: false
        },
         modeltype :{
            type: String,
            required: false
        },
    },
    data() {
        return {
            configId: '',
            isShown:false
        };
    },
     mounted() {
        this.$nextTick(() => {
            setTimeout(() => {
                this.isShown = true;  // adds .show ? triggers transform transition
            }, 50);
        });
    },
    created() {
        this.configId = this.modelDetail.CONFIGURATION_ID?.toString() || '';
        this.clientId = this.modelDetail.RULE_CLIENT_ID?.toString() || '';
    },
    methods: {
        close() {
            this.$parent.modelopen = false;
        }
    }
};
</script>

